insert into `pl_plan_material_parameter` (material_code, logical_plant_no, logical_plant_name, plan_type, demand_type, demand_strategy_code, vendor_lead_time, planning_time_fence, demand_time_fence, order_quantity, min_order_quantity, order_cycle_time, safety_stock_cal_type, safety_stock, safety_stock_factors, loss_rate, finished_rate, creator_id, updator_id, tenant_id,operator_name,material_desc,transfer_logical_plant_no) values
(#{item.materialCode}, #{item.logicalPlantNo}, #{item.logicalPlantName}, #{item.planType}, #{item.demandType}, #{item.demandStrategyCode}, #{item.vendorLeadTime}, #{item.planningTimeFence}, #{item.demandTimeFence}, #{item.orderQuantity}, #{item.minOrderQuantity}, #{item.orderCycleTime}, #{item.safetyStockCalType}, #{item.safetyStock}, #{item.safetyStockFactors}, #{item.lossRate}, #{item.finishedRate}, #{item.createUserId}, #{item.updateUserId}, #{item.tenantId},#{item.operatorName},#{item.materialDesc} ,#{item.transferLogicalPlantNo})
ON DUPLICATE key update plan_type = values(plan_type), demand_type = values(demand_type), demand_strategy_code = values(demand_strategy_code), plan_type = values(plan_type), vendor_lead_time = values(vendor_lead_time), planning_time_fence = values(planning_time_fence), demand_time_fence = values(demand_time_fence), order_quantity = values(order_quantity), min_order_quantity = values(min_order_quantity), order_cycle_time = values(order_cycle_time), safety_stock_cal_type = values(safety_stock_cal_type), safety_stock = values(safety_stock), safety_stock_factors = values(safety_stock_factors), loss_rate = values(loss_rate), finished_rate = values(finished_rate), updator_id = values(updator_id), update_time = values(update_time), operator_name = values(operator_name), material_desc = values(material_desc), transfer_logical_plant_no = values(transfer_logical_plant_no);

