select

from `pl_plan_material_parameter`
where tenant_id = #{tenantId}
and deleted = 0
and logical_plant_no = #{logicalPlantNo}
and material_code = #{materialCode}

select

from `pl_plan_material_parameter`
where tenant_id = #{tenantId}
and logical_plant_no = #{logicalPlantNo}

    and material_code = #{materialCode}


    and operator_name = #{operatorName}

and deleted = 0
order by update_time desc

select
logical_plant_no
from `pl_plan_material_parameter`
where
tenant_id = #{tenantId}

    and logical_plant_no != #{logicalPlantNo}

and material_code = #{materialCode}
and deleted != 1
